import jwt
import datetime


def generate_token(user):
    payload = {
        'exp': datetime.datetime.utcnow() + datetime.timedelta(days=1),
        'iat': datetime.datetime.utcnow(),
        'sub': user['id']
    }

    return jwt.encode(payload, 'secret', algorithm='HS256')